import { test, expect } from '@playwright/test';
import path from 'path';
import { fileURLToPath } from 'url';
const __dirname = path.dirname(fileURLToPath(import.meta.url));
const localUrl = `file://${path.resolve(__dirname, 'target-app/profile.html')}`;
test.describe('Profile Page', () => {
  let bioInput;
  let updateButton;
  let errorMessage;
  let updatedMessage;
  test.describe.configure({
    timeout: 60000
  });
  test.beforeEach(async ({
    page
  }) => {
    await page.goto(localUrl, {
      timeout: 60000
    });
    bioInput = page.getByLabel('Bio');
    updateButton = page.getByRole('button', {
      name: 'Update'
    });
    errorMessage = page.locator('#bio-error');
    updatedMessage = page.locator('#bio-updated');
  });
  test('Profile page loads with correct title and empty form', async ({
    page
  }) => {
    await expect(page).toHaveTitle('Profile — AutoHeal Demo');
    await expect(bioInput).toBeVisible();
    await expect(updateButton).toBeVisible();
    await expect(errorMessage).toHaveText('');
    await expect(updatedMessage).toHaveText('');
  });
  test('Submitting empty bio displays validation error', async () => {
    await updateButton.click();
    await expect(errorMessage).toHaveText('Bio cannot be empty.');
    await expect(updatedMessage).toHaveText('');
  });
  test('Submitting non-empty bio displays success message', async () => {
    const sampleBio = 'Experienced automation engineer with a passion for clean code and reliable tests.';
    await bioInput.fill(sampleBio);
    await updateButton.click();
    await expect(errorMessage).toHaveText('');
    await expect(updatedMessage).toHaveText('Bio updated successfully.');
  });
  test('Success message clears and error reappears after empty submission', async () => {
    await bioInput.fill('Valid bio content');
    await updateButton.click();
    await expect(updatedMessage).toHaveText('Bio updated successfully.');
    await bioInput.clear();
    await updateButton.click();
    await expect(errorMessage).toHaveText('Bio cannot be empty.');
    await expect(updatedMessage).toHaveText('');
  });
  test('Error message clears and success appears after valid submission', async () => {
    await updateButton.click();
    await expect(errorMessage).toHaveText('Bio cannot be empty.');
    await bioInput.fill('New valid bio');
    await updateButton.click();
    await expect(errorMessage).toHaveText('');
    await expect(updatedMessage).toHaveText('Bio updated successfully.');
  });
  test('Updating bio multiple times shows success each time', async () => {
    const bio1 = 'First bio entry';
    const bio2 = 'Second bio entry with more details';
    const bio3 = 'Final bio with even more information';
    await bioInput.fill(bio1);
    await updateButton.click();
    await expect(updatedMessage).toHaveText('Bio updated successfully.');
    await bioInput.fill(bio2);
    await updateButton.click();
    await expect(updatedMessage).toHaveText('Bio updated successfully.');
    await bioInput.fill(bio3);
    await updateButton.click();
    await expect(updatedMessage).toHaveText('Bio updated successfully.');
  });
});
